px","size":5,"sizes":[]},"border_radius":{"unit":"px","size":0,"sizes":[]},"header_background_color":"#ABB6CB","header_text_color":"#324059","header_typography_typography":"custom","header_typography_font_family":"Montserrat","header_typography_font_size":{"unit":"px","size":24,"sizes":[]},"header_typography_font_weight":"bold","header_separator_width":{"unit":"px","size":0,"sizes":[]},"item_text_color_normal":"#324059","item_text_color_hover":"#61CE70","item_text_underline_hover":"","__globals__":{"header_typography_typography":"globals/typography?id=8f3b7a5","background_color":"globals/colors?id=2c1b11c","item_text_color_normal":"globals/colors?id=primary","item_text_color_hover":"globals/colors?id=42f7068a","loader_color":"","header_background_color":"","header_text_color":"globals/colors?id=primary","marker_color":"globals/colors?id=primary"}},"elements":[],"widgetType":"table-of-contents"},{"id":"7843503","elType":"widget","settings":{"title":"La subsecuencia de suma máxima","size":"xl","__globals__":{"typography_typography":"globals/typography?id=secondary"},"_padding":{"unit":"%","top":"3","right":"0","bottom":"0","left":"0","isLinked":false},"_padding_tablet":{"unit":"%","top":"","right":"","bottom":"","left":"","isLinked":true},"_padding_mobile":{"unit":"%","top":"","right":"","bottom":"","left":"","isLinked":true},"header_size":"h3"},"elements":[],"widgetType":"heading"},{"id":"ba2ab1d","elType":"widget","settings":{"editor":"<p>El problema de la subsecuencia de suma máxima consiste en encontrar la subsecuencia de una secuencia dada que tiene la suma máxima. Por ejemplo, dada la secuencia [-2, 1, -3, 4, -1, 2, 1, -5, 4], la subsecuencia de suma máxima es [4, -1, 2, 1], ya que su suma es 6.</p><p>A continuación se presenta un algoritmo en Java para resolver este problema:</p><ol><li><p>Declara una variable <b><code>maxSum</code> </b>inicializada en el valor mínimo posible de un <code><b>int</b></code>. Esta variable se utilizará para almacenar la suma máxima encontrada hasta el momento.</p></li><li><p>Recorre la secuencia elemento por elemento. En cada iteración del bucle, actualiza la variable <b><code>maxSum</code> </b>comparando el valor actual de <b><code>maxSum</code> </b>con la suma de la subsecuencia hasta el elemento actual.</p></li><li><p>Para calcular la suma de la subsecuencia hasta el elemento actual, se puede utilizar otra variable, llamada <code><b>currentsum</b></code>, inicializada en 0. En cada iteración del bucle, se añade el elemento actual a <b><code>currentSum</code> </b>y se actualiza <b><code>maxSum</code> </b>si <b><code>currentSum</code> </b>es mayor que <code><b>maxSum</b></code>. Si <b><code>currentSum</code> </b>es menor que 0, se debe reiniciar a 0, ya que cualquier subsecuencia que incluya elementos negativos siempre será menor que cualquier subsecuencia que no los incluya.</p></li></ol><p><span style="color: var( --e-global-color-text ); font-family: var( --e-global-typography-text-font-family ), Sans-serif; font-size: var( --e-global-typography-text-font-size ); font-weight: var( --e-global-typography-text-font-weight ); letter-spacing: var( --e-global-typography-text-letter-spacing );">A continuación se muestra un ejemplo de código en Java que implementa este algoritmo:</span></p>","typography_font_size":{"unit":"px","size":20,"sizes":[]},"typography_font_weight":"400","typography_line_height":{"unit":"em","size":2,"sizes":[]}},"elements":[],"widgetType":"text-editor"},{"id":"a1a9dcc","elType":"widget","settings":{"language":"java","code":"    public static int maxSumaMaxima(int[] arr) {
    
        // Inicializar la suma máxima y la suma actual con el primer elemento del Array
        int maxSum = arr[0];
        int currentSum = 0;
        
        // Recorrer el Array elemento por elemento
        for (int i = 0; i < arr.length; i++) {
            
            // Actualizar la suma actual sumándole el elemento actual
            currentSum += arr[i];
    
            // Si la suma actual es mayor que la suma máxima, actualizar la suma máxima
            maxSum = Math.max(maxSum, currentSum);
    
            // Si la suma actual es negativa, reiniciarla a 0
            if (currentSum < 0) {
                currentSum = 0;
            }
        }

        // Devolver la suma máxima encontrada
        return maxSum;
    }

   

