static void cuad(int altura, int base)
{
    if(altura>0) 
    {            
        cuad2(base);//método recursivo que crea los elementos de cada línea
        cuad(altura-1, base);//llamada recursiva
    }          
}

//crea los elementos de cada línea
static void cuad2(int n)
{
    if(n>0) 
